 Begin SpecMap 	# Conversion between spectral coordinate systems
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Nspec = 3 	# Number of conversion steps
    Spec1 = "FRTOVL" 	# Convert frequency to rel. velocity
    Spec1a = 1400000000 	# Rest frequency (Hz)
    Spec2 = "VLTOFR" 	# Convert rel. velocity to frequency
    Spec2a = 1400000000 	# Rest frequency (Hz)
    Spec3 = "ENTOFR" 	# Convert energy to frequency
 End SpecMap
